import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { gsap } from 'gsap';
import { LogOut, Package, User, Settings, ChevronRight, Crown, Tag, Trash2, ShieldCheck, Mail, Phone, Calendar } from 'lucide-react';
import { useTheme } from '../context/ThemeContext';
import { useAuth } from '../context/AuthContext';
import { ordersAPI, offersAPI } from '../utils/api';
import Navbar from '../components/Navbar';
import Footer from '../components/Footer';
import toast from 'react-hot-toast';

export default function CustomerDashboard() {
  const navigate = useNavigate();
  const { isDark } = useTheme();
  const { user, logout } = useAuth();
  const [activeTab, setActiveTab] = useState('orders');
  const [orders, setOrders] = useState([]);
  const [offers, setOffers] = useState([]);
  const [loading, setLoading] = useState(true);
  const containerRef = useRef(null);

  useEffect(() => {
    fetchData();
    gsap.fromTo(containerRef.current, { opacity: 0, y: 20 }, { opacity: 1, y: 0, duration: 0.6, ease: 'power3.out' });
  }, []);

  const fetchData = async () => {
    setLoading(true);
    try {
      const [ordersRes, offersRes] = await Promise.all([
        ordersAPI.getMyOrders(),
        offersAPI.getAll()
      ]);
      setOrders(ordersRes.data.orders);
      setOffers(offersRes.data.offers.filter(o => o.isActive));
    } catch (err) {
      toast.error('Failed to load dashboard data');
    } finally {
      setLoading(false);
    }
  };

  const handleCancelOrder = async (orderId) => {
    if (!window.confirm('Are you sure you want to cancel this order?')) return;

    try {
      await ordersAPI.cancelOrder(orderId);
      toast.success('Order cancelled successfully');
      fetchData(); // Refresh list
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to cancel order');
    }
  };

  const statusColors = {
    pending: isDark ? 'bg-yellow-900/20 text-yellow-400' : 'bg-yellow-100 text-yellow-700',
    confirmed: isDark ? 'bg-blue-900/20 text-blue-400' : 'bg-blue-100 text-blue-700',
    preparing: isDark ? 'bg-orange-900/20 text-orange-400' : 'bg-orange-100 text-orange-700',
    ready: isDark ? 'bg-bk-gold/20 text-bk-gold' : 'bg-yellow-100 text-yellow-800',
    delivered: isDark ? 'bg-green-900/20 text-green-400' : 'bg-green-100 text-green-700',
    completed: isDark ? 'bg-green-900/30 text-green-300' : 'bg-green-200 text-green-800',
    cancelled: isDark ? 'bg-red-900/20 text-red-400' : 'bg-red-100 text-red-700',
  };

  const handleLogout = () => {
    logout();
    toast.success('Logged out successfully!');
    navigate('/login');
  };

  if (!user) return null;

  return (
    <div className={isDark ? 'bg-bk-dark' : 'bg-slate-50'}>
      <Navbar />
      <div ref={containerRef} className="min-h-screen pb-20">
        <div className="max-w-6xl mx-auto px-4 py-8">
          {/* Header */}
          <div className={`rounded-2xl p-8 border mb-8 relative overflow-hidden ${isDark ? 'bg-bk-dark-2 border-bk-brown-light/20' : 'bg-white border-gray-200'}`}>
            <div className="absolute top-0 right-0 p-8 opacity-10">
              <Crown size={120} className="text-bk-gold" />
            </div>
            <div className="relative z-10 flex flex-col md:flex-row items-center justify-between gap-6">
              <div className="flex items-center gap-6">
                <div className="w-20 h-20 rounded-2xl bg-gold-gradient flex items-center justify-center text-bk-dark text-3xl font-black shadow-gold">
                  {user.name.charAt(0)}
                </div>
                <div>
                  <h1 className={`font-heading text-3xl font-black mb-1 ${isDark ? 'text-bk-cream' : 'text-gray-900'}`}>
                    Welcome, {user.name.split(' ')[0]}! 👋
                  </h1>
                  <div className="flex flex-wrap gap-4 mt-2">
                    <span className="flex items-center gap-1.5 text-xs font-bold text-bk-gold bg-bk-gold/10 px-3 py-1 rounded-full">
                      <Crown size={14} /> {user.crownPoints || 0} Crown Points
                    </span>
                    <span className={`flex items-center gap-1.5 text-xs font-bold px-3 py-1 rounded-full ${isDark ? 'bg-bk-dark text-bk-cream/50' : 'bg-gray-100 text-gray-500'}`}>
                      <ShieldCheck size={14} /> Verified Member
                    </span>
                  </div>
                </div>
              </div>
              <button onClick={handleLogout}
                className={`flex items-center gap-2 px-6 py-3 rounded-xl font-heading font-bold transition-all ${
                  isDark
                    ? 'bg-bk-dark text-bk-cream hover:text-bk-yellow border border-bk-brown-light/30'
                    : 'bg-gray-100 text-gray-900 hover:bg-gray-200 border border-gray-300'
                }`}>
                <LogOut size={18} />
                Logout
              </button>
            </div>
          </div>

          {/* Tabs */}
          <div className="flex gap-4 mb-8 border-b overflow-x-auto scrollbar-hide" role="tablist">
            {[
              { id: 'orders', label: 'My Orders', icon: Package },
              { id: 'coupons', label: 'Rewards & Coupons', icon: Tag },
              { id: 'profile', label: 'Account Details', icon: User },
              { id: 'settings', label: 'Settings', icon: Settings },
            ].map(tab => {
              const Icon = tab.icon;
              return (
                <button key={tab.id}
                  onClick={() => setActiveTab(tab.id)}
                  className={`px-6 py-4 font-heading font-bold border-b-2 transition-all flex items-center gap-2 flex-shrink-0 ${
                    activeTab === tab.id
                      ? isDark ? 'border-bk-gold text-bk-gold' : 'border-bk-red text-bk-red'
                      : isDark ? 'border-transparent text-bk-cream/50 hover:text-bk-cream' : 'border-transparent text-gray-600 hover:text-gray-900'
                  }`}
                  role="tab"
                  aria-selected={activeTab === tab.id}>
                  <Icon size={18} />
                  {tab.label}
                </button>
              );
            })}
          </div>

          {/* Tab Content */}
          {activeTab === 'orders' && (
            <div className="space-y-4">
              {loading ? (
                <div className="py-12 text-center text-bk-cream/30">Loading your orders...</div>
              ) : orders.length > 0 ? (
                orders.map(order => (
                  <div key={order._id}
                    className={`rounded-2xl p-6 border group transition-all ${
                      isDark ? 'bg-bk-dark-2 border-bk-brown-light/10 hover:border-bk-gold/20' : 'bg-white border-gray-200 hover:shadow-md'
                    }`}>
                    <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-4 mb-4">
                      <div>
                        <div className="flex items-center gap-3">
                          <h3 className={`font-heading text-lg font-bold ${isDark ? 'text-bk-cream' : 'text-gray-900'}`}>
                            {order.orderNumber}
                          </h3>
                          <span className={`px-3 py-1 rounded-full text-[10px] font-heading font-black uppercase tracking-wider ${statusColors[order.status]}`}>
                            {order.status}
                          </span>
                        </div>
                        <p className={`font-body text-xs mt-1 ${isDark ? 'text-bk-cream/40' : 'text-gray-500'}`}>
                          Placed on {new Date(order.createdAt).toLocaleDateString(undefined, { dateStyle: 'long' })} at {new Date(order.createdAt).toLocaleTimeString(undefined, { timeStyle: 'short' })}
                        </p>
                      </div>
                      <div className="flex items-center gap-3 w-full md:w-auto">
                        {['pending', 'confirmed'].includes(order.status) && (
                          <button onClick={() => handleCancelOrder(order._id)}
                            className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-2 rounded-lg bg-red-500/10 text-red-500 text-xs font-bold hover:bg-red-500 hover:text-white transition-all">
                            <Trash2 size={14} /> Cancel Order
                          </button>
                        )}
                        <button onClick={() => navigate(`/order-confirm/${order._id}`)}
                          className={`flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-2 rounded-lg text-xs font-bold transition-all ${
                            isDark ? 'bg-bk-dark text-bk-gold border border-bk-gold/20 hover:border-bk-gold' : 'border border-gray-300 text-gray-700 hover:bg-gray-50'
                          }`}>
                          Track <ChevronRight size={14} />
                        </button>
                      </div>
                    </div>

                    <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 py-4 border-t border-b" style={{borderColor: isDark ? 'rgba(200, 150, 42, 0.05)' : 'rgb(243, 244, 246)'}}>
                      <div>
                        <p className={`text-[10px] font-heading uppercase tracking-widest mb-1 ${isDark ? 'text-bk-cream/30' : 'text-gray-400'}`}>Items</p>
                        <ul className={`text-xs ${isDark ? 'text-bk-cream/70' : 'text-gray-700'} space-y-0.5`}>
                          {order.items.map((item, idx) => (
                            <li key={idx} className="line-clamp-1">{item.quantity}× {item.name}</li>
                          ))}
                        </ul>
                      </div>
                      <div>
                        <p className={`text-[10px] font-heading uppercase tracking-widest mb-1 ${isDark ? 'text-bk-cream/30' : 'text-gray-400'}`}>Total Amount</p>
                        <p className={`font-heading font-black text-lg ${isDark ? 'text-bk-yellow' : 'text-bk-red'}`}>₹{order.total}</p>
                      </div>
                      <div>
                        <p className={`text-[10px] font-heading uppercase tracking-widest mb-1 ${isDark ? 'text-bk-cream/30' : 'text-gray-400'}`}>Payment</p>
                        <p className={`text-xs font-bold uppercase ${isDark ? 'text-bk-cream/80' : 'text-gray-800'}`}>{order.paymentMethod}</p>
                        <p className={`text-[9px] font-bold ${order.paymentStatus === 'paid' ? 'text-green-500' : 'text-yellow-500'}`}>{order.paymentStatus}</p>
                      </div>
                      <div>
                        <p className={`text-[10px] font-heading uppercase tracking-widest mb-1 ${isDark ? 'text-bk-cream/30' : 'text-gray-400'}`}>Type</p>
                        <p className={`text-xs font-bold uppercase ${isDark ? 'text-bk-cream/80' : 'text-gray-800'}`}>{order.orderType.replace('-', ' ')}</p>
                        {order.tableNumber && <p className="text-[9px] text-bk-gold font-bold">Table {order.tableNumber}</p>}
                      </div>
                    </div>
                  </div>
                ))
              ) : (
                <div className={`rounded-2xl p-12 text-center border ${isDark ? 'bg-bk-dark-2 border-bk-brown-light/10' : 'bg-white border-gray-200'}`}>
                  <div className="w-16 h-16 bg-bk-gold/10 rounded-full flex items-center justify-center mx-auto mb-4">
                    <Package size={24} className="text-bk-gold" />
                  </div>
                  <h3 className={`font-heading text-lg font-bold mb-1 ${isDark ? 'text-bk-cream' : 'text-gray-900'}`}>No orders yet</h3>
                  <p className={`font-body text-sm mb-6 ${isDark ? 'text-bk-cream/40' : 'text-gray-500'}`}>Start your flame-grilled journey today!</p>
                  <button onClick={() => navigate('/menu')} className="btn-gold px-8 py-2.5">Browse Menu</button>
                </div>
              )}
            </div>
          )}

          {activeTab === 'coupons' && (
            <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-4">
              {offers.length > 0 ? offers.map(offer => (
                <div key={offer._id} className={`p-5 rounded-2xl border-2 border-dashed relative overflow-hidden transition-all ${
                  isDark ? 'bg-bk-dark-2 border-bk-gold/20 hover:border-bk-gold/40' : 'bg-white border-gray-200 hover:border-bk-red/20'
                }`}>
                  <div className="flex items-start justify-between mb-4">
                    <div className="w-10 h-10 bg-bk-red/10 text-bk-red rounded-lg flex items-center justify-center">
                      <Tag size={20} />
                    </div>
                    <div className="bg-bk-gold text-bk-dark text-[10px] font-black px-2 py-0.5 rounded-full uppercase">
                      {offer.type === 'percentage' ? `${offer.value}% OFF` : `₹${offer.value} OFF`}
                    </div>
                  </div>
                  <h4 className={`font-heading font-bold text-base mb-1 ${isDark ? 'text-bk-cream' : 'text-gray-900'}`}>{offer.title}</h4>
                  <p className={`text-xs font-body mb-4 line-clamp-2 ${isDark ? 'text-bk-cream/50' : 'text-gray-500'}`}>{offer.description}</p>
                  <div className={`mt-auto pt-4 border-t flex items-center justify-between ${isDark ? 'border-bk-brown-light/10' : 'border-gray-50'}`}>
                    <span className="font-heading text-bk-gold font-bold text-sm tracking-widest">{offer.code}</span>
                    <button onClick={() => { navigator.clipboard.writeText(offer.code); toast.success('Code copied!'); }}
                      className="text-[10px] font-bold text-bk-cream/30 hover:text-bk-cream uppercase transition-colors">Copy Code</button>
                  </div>
                </div>
              )) : (
                <div className="col-span-full py-12 text-center text-bk-cream/30 italic">No available coupons at this time. Check back soon!</div>
              )}
            </div>
          )}

          {activeTab === 'profile' && (
            <div className={`rounded-2xl p-8 border ${isDark ? 'bg-bk-dark-2 border-bk-brown-light/20' : 'bg-white border-gray-200'}`}>
              <h3 className={`font-heading text-xl font-bold mb-8 flex items-center gap-2 ${isDark ? 'text-bk-cream' : 'text-gray-900'}`}>
                <User size={24} className="text-bk-gold" /> Account Credentials
              </h3>
              <div className="grid md:grid-cols-2 gap-8">
                <div className="space-y-6">
                  <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-xl flex items-center justify-center ${isDark ? 'bg-bk-dark' : 'bg-gray-100'} text-bk-gold`}>
                      <User size={20} />
                    </div>
                    <div>
                      <p className={`text-[10px] uppercase tracking-widest font-bold ${isDark ? 'text-bk-cream/30' : 'text-gray-400'}`}>Full Name</p>
                      <p className={`font-heading font-bold ${isDark ? 'text-bk-cream' : 'text-gray-900'}`}>{user.name}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-xl flex items-center justify-center ${isDark ? 'bg-bk-dark' : 'bg-gray-100'} text-bk-gold`}>
                      <Mail size={20} />
                    </div>
                    <div>
                      <p className={`text-[10px] uppercase tracking-widest font-bold ${isDark ? 'text-bk-cream/30' : 'text-gray-400'}`}>Email Address</p>
                      <p className={`font-heading font-bold ${isDark ? 'text-bk-cream' : 'text-gray-900'}`}>{user.email}</p>
                    </div>
                  </div>
                </div>
                <div className="space-y-6">
                  <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-xl flex items-center justify-center ${isDark ? 'bg-bk-dark' : 'bg-gray-100'} text-bk-gold`}>
                      <Phone size={20} />
                    </div>
                    <div>
                      <p className={`text-[10px] uppercase tracking-widest font-bold ${isDark ? 'text-bk-cream/30' : 'text-gray-400'}`}>Phone Number</p>
                      <p className={`font-heading font-bold ${isDark ? 'text-bk-cream' : 'text-gray-900'}`}>{user.phone || 'Not provided'}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-xl flex items-center justify-center ${isDark ? 'bg-bk-dark' : 'bg-gray-100'} text-bk-gold`}>
                      <Calendar size={20} />
                    </div>
                    <div>
                      <p className={`text-[10px] uppercase tracking-widest font-bold ${isDark ? 'text-bk-cream/30' : 'text-gray-400'}`}>Member Since</p>
                      <p className={`font-heading font-bold ${isDark ? 'text-bk-cream' : 'text-gray-900'}`}>{new Date(user.createdAt || Date.now()).toLocaleDateString(undefined, { month: 'long', year: 'numeric' })}</p>
                    </div>
                  </div>
                </div>
              </div>
              <div className="mt-12 flex flex-wrap gap-4 pt-8 border-t border-bk-gold/10">
                <button className={`px-6 py-3 rounded-lg font-heading font-bold transition-all ${
                  isDark ? 'bg-gold-gradient text-bk-dark shadow-gold' : 'bg-bk-red text-white'
                }`}>Update Profile</button>
                <button className={`px-6 py-3 rounded-lg font-heading font-bold border transition-all ${
                  isDark ? 'border-bk-brown-light/30 text-bk-cream/60 hover:text-bk-cream' : 'border-gray-300 text-gray-600'
                }`}>Change Password</button>
              </div>
            </div>
          )}

          {activeTab === 'settings' && (
            <div className={`rounded-2xl p-8 border ${isDark ? 'bg-bk-dark-2 border-bk-brown-light/20' : 'bg-white border-gray-200'}`}>
              <h3 className={`font-heading text-xl font-bold mb-6 ${isDark ? 'text-bk-cream' : 'text-gray-900'}`}>Notification Preferences</h3>
              <div className="space-y-4 max-w-md">
                {[
                  { label: 'Email notifications for orders', desc: 'Receive real-time updates via email' },
                  { label: 'SMS updates for delivery', desc: 'Get tracked links on your phone' },
                  { label: 'Weekly promotional offers', desc: 'Never miss a Whopper deal' },
                ].map((s, i) => (
                  <label key={i} className={`flex items-center justify-between p-4 rounded-xl border transition-all cursor-pointer ${isDark ? 'bg-bk-dark border-bk-brown-light/10 hover:border-bk-gold/20' : 'bg-gray-50 border-gray-100'}`}>
                    <div>
                      <p className={`font-heading font-bold text-xs ${isDark ? 'text-bk-cream' : 'text-gray-900'}`}>{s.label}</p>
                      <p className={`text-[10px] font-body ${isDark ? 'text-bk-cream/40' : 'text-gray-500'}`}>{s.desc}</p>
                    </div>
                    <div className="relative inline-flex items-center cursor-pointer">
                      <input type="checkbox" className="sr-only peer" defaultChecked={i < 2} />
                      <div className="w-9 h-5 bg-gray-500 rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-4 after:w-4 after:transition-all peer-checked:bg-bk-gold" />
                    </div>
                  </label>
                ))}
              </div>
              <button className={`mt-10 px-8 py-3 rounded-xl font-heading font-bold transition-all ${
                isDark ? 'bg-gold-gradient text-bk-dark' : 'bg-bk-red text-white'
              }`}>Save Settings</button>
            </div>
          )}
        </div>
      </div>
      <Footer />
    </div>
  );
}
